const results = Array.isArray(msg.payload) ? msg.payload : [];

let passCount = 0;
let failCount = 0;
const failingNames = [];

for (const r of results) {
    if (r && r.status === 'PASS') {
        passCount++;
    } else {
        failCount++;
        // Try common name fields.
        const name = r && (r.relay_name || r.name || r.input_name || r.output_name || r.control_name || 'unnamed');
        failingNames.push(name);
    }
}

msg.payload = {
    overall_status: (results.length > 0 && failCount === 0) ? 'PASS' : 'FAIL',
    pass_count: passCount,
    fail_count: failCount,
    total: results.length,
    failing_names: failingNames,
    timestamp: new Date().toISOString()
};
return msg;
